SELECT MAX(rate_per_100k) AS max_rate
FROM chlamydia_rates
WHERE age_group = '15-24' AND year = 2023;

SELECT AVG(value) AS average_obesity_rate
FROM county_data
WHERE indicator_id = 0 AND year = 2021;

SELECT AVG(value) AS average_value
FROM county_data
WHERE year = 2021;

SELECT AVG(rate_per_100k) AS average_rate
FROM chlamydia_rates
WHERE year = 2021 AND age_group = '15-24';

SELECT county_id, rate_per_100k
FROM chlamydia_rates
WHERE year = 2021;
